from __future__ import annotations

import base64
import io
import os
from dataclasses import dataclass
from typing import Dict, List, Optional, Tuple

import numpy as np
import cv2
from fastapi import FastAPI, File, UploadFile, HTTPException
from pydantic import BaseModel
from PIL import Image
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from sklearn.calibration import CalibratedClassifierCV
import pickle

try:
    import face_recognition
except Exception as e:
    raise RuntimeError("face_recognition library is required") from e


MODEL_DIR = os.environ.get("FACE_MODEL_DIR", "./face_model")
EMBEDDINGS_PATH = os.path.join(MODEL_DIR, "embeddings.pkl")
CLASSIFIER_PATH = os.path.join(MODEL_DIR, "classifier.pkl")
LABELS_PATH = os.path.join(MODEL_DIR, "labels.pkl")

app = FastAPI(title="Facial Recognition API", version="1.0")


class PredictResponse(BaseModel):
    best_match: Optional[str]
    confidence: float
    probabilities: Dict[str, float]
    detected_faces: int


@dataclass
class TrainingData:
    embeddings: np.ndarray
    labels: List[str]


def ensure_model_dir() -> None:
    os.makedirs(MODEL_DIR, exist_ok=True)


def load_image_bytes(file_bytes: bytes) -> np.ndarray:
    image = Image.open(io.BytesIO(file_bytes)).convert("RGB")
    return np.array(image)


def extract_face_embeddings(image: np.ndarray) -> List[np.ndarray]:
    locations = face_recognition.face_locations(image, model="hog")
    encodings = face_recognition.face_encodings(image, known_face_locations=locations)
    return encodings


def train_classifier(embeddings: np.ndarray, labels: List[str]) -> Tuple[LabelEncoder, CalibratedClassifierCV]:
    le = LabelEncoder()
    y = le.fit_transform(labels)
    clf = SVC(kernel="linear", probability=True, class_weight="balanced")
    calibrated = CalibratedClassifierCV(clf, method="sigmoid", cv=3)
    calibrated.fit(embeddings, y)
    return le, calibrated


def save_model(data: TrainingData, le: LabelEncoder, clf: CalibratedClassifierCV) -> None:
    ensure_model_dir()
    with open(EMBEDDINGS_PATH, "wb") as f:
        pickle.dump(data.embeddings, f)
    with open(LABELS_PATH, "wb") as f:
        pickle.dump(le, f)
    with open(CLASSIFIER_PATH, "wb") as f:
        pickle.dump(clf, f)


def load_model():
    if not (os.path.exists(EMBEDDINGS_PATH) and os.path.exists(CLASSIFIER_PATH) and os.path.exists(LABELS_PATH)):
        return None, None
    with open(EMBEDDINGS_PATH, "rb") as f:
        embeddings = pickle.load(f)
    with open(LABELS_PATH, "rb") as f:
        le = pickle.load(f)
    with open(CLASSIFIER_PATH, "rb") as f:
        clf = pickle.load(f)
    return (embeddings, le, clf)


@app.on_event("startup")
def startup_event():
    ensure_model_dir()


@app.post("/train")
async def train_endpoint(files: List[UploadFile] = File(...), labels: List[str] = File(...)):
    if len(files) != len(labels):
        raise HTTPException(status_code=400, detail="files and labels length mismatch")

    embeddings_list: List[np.ndarray] = []
    labels_list: List[str] = []

    for file, label in zip(files, labels):
        content = await file.read()
        image = load_image_bytes(content)
        encodings = extract_face_embeddings(image)
        if len(encodings) == 0:
            continue
        for enc in encodings:
            embeddings_list.append(enc)
            labels_list.append(label)

    if not embeddings_list:
        raise HTTPException(status_code=400, detail="No faces found in training images")

    embeddings = np.array(embeddings_list)
    data = TrainingData(embeddings=embeddings, labels=labels_list)
    le, clf = train_classifier(embeddings, labels_list)
    save_model(data, le, clf)

    return {
        "status": "trained",
        "num_samples": len(labels_list),
        "num_classes": len(le.classes_),
        "classes": list(le.classes_),
    }


@app.post("/predict", response_model=PredictResponse)
async def predict_endpoint(file: UploadFile = File(...)):
    model = load_model()
    if model[1] is None:
        raise HTTPException(status_code=400, detail="Model not trained")

    _, le, clf = model
    content = await file.read()
    image = load_image_bytes(content)
    encodings = extract_face_embeddings(image)

    if len(encodings) == 0:
        raise HTTPException(status_code=400, detail="No face detected")

    probs_accum = np.zeros(len(le.classes_), dtype=np.float64)
    for enc in encodings:
        prob = clf.predict_proba([enc])[0]
        probs_accum += prob

    probs = probs_accum / len(encodings)
    prob_map = {cls: float(p) for cls, p in zip(le.classes_, probs)}
    best_idx = int(np.argmax(probs))
    best_match = str(le.classes_[best_idx]) if probs.size else None
    confidence = float(probs[best_idx]) if probs.size else 0.0

    return PredictResponse(
        best_match=best_match,
        confidence=confidence,
        probabilities=prob_map,
        detected_faces=len(encodings),
    )


@app.get("/health")
def health():
    return {"status": "ok"}


@app.get("/classes")
def list_classes():
    model = load_model()
    if model[1] is None:
        return {"classes": []}
    _, le, _ = model
    return {"classes": list(le.classes_)}


